var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"해, 해냈어. 괴수들이 물러난다!","JPN":"や、やった。怪獣が退いていく！","ENG":"W-we did it! The monsters are retreating!","TWN":"成功了，我們成功了。怪獸們撤退了！"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"전부 해치웠어! 우리가 이긴 거야!","JPN":"全部やっつけたぞ！　俺たちが勝ったんだ！","ENG":"They're all down! We won!","TWN":"全部解決了！我們贏了！"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"우리가… 정말 이긴 건가?","JPN":"本当に私たちが……勝ったのか？","ENG":"Did... Did we really win?","TWN":"我們……真的贏了嗎？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"하하! 대장님, 설마 우시는 거 아니죠?","JPN":"はは！　隊長、まさか泣いてないですよね？","ENG":"Haha! Don't tell me you're crying, Captain!","TWN":"哈哈！隊長，你不會哭了吧？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"야 인마. 소녀 같은 대장님 마음에 상처를 입히면 어떡해?","JPN":"おい、乙女のような隊長の心を傷つけちゃダメだろう？","ENG":"Hey, come on. Don't wound the tender heart of our maidenly Captain!","TWN":"喂，臭小子。隊長可是少女心，你這樣受傷。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"저흰 괜찮습니다, 대장님. 어차피 투구에 가려져서 보이지도 않으니 마음껏 우세요.","JPN":"私たちは大丈夫ですよ、隊長。どうせ兜のせいで見えませんから、思う存分泣いてください。","ENG":"We're fine, Captain. With those helmets on, no one can see anyway. Cry all you want.","TWN":"不用在乎我們，隊長。反正被頭盔遮住了也看不見，盡情哭吧。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"전 소녀도 아니고, 운 적도 없습니다!","JPN":"私は乙女でもないし、泣いたこともありません！","ENG":"I am not a maiden, and I did not cry!","TWN":"我才不是少女心呢，我才沒哭！"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……휴우.","JPN":"……ふう。","ENG":"...Phew.","TWN":"……呼。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"고생하셨습니다. 에스테로사 경 덕분에 별다른 피해 없이 끝났네요.","JPN":"お疲れ様でした。エステロサ卿のおかげで、大した被害もなく終わりましたね。","ENG":"Great work. Thanks to you, Dame Esterosa, we made it through with barely any casualties.","TWN":"你辛苦了。多虧了艾斯特洛索，我們才能毫無損傷地結束這次事件。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아닙니다. 여러분이 노력하신 덕분이죠.","JPN":"いいえ。皆さんが頑張ってくれたおかげです。","ENG":"No, it was all of you. Your efforts made it possible.","TWN":"不，這都是你們努力的結果。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"전부 끝났으니, 이제 돌아가면…….","JPN":"すべて終わりましたので、もう戻れば……","ENG":"It's all over now. So we can finally head ba–","TWN":"既然都結束了，現在回去吧……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어……?","JPN":"えっ……？","ENG":"...Huh?","TWN":"呃……？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"왜 그러십니까?","JPN":"どうしましたか？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아, 아닙니다. 방금 무척이나 섬뜩한 느낌이 든 것 같아서요.","JPN":"あ、いいえ。今、とてもぞっとするような気がして。","ENG":"I-It's nothing. I just felt something. A chill.","TWN":"啊，不是的。剛才好像有種非常毛骨悚然的感覺。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이 느낌은, 마치…….","JPN":"この感覚は、まるで……","ENG":"It felt like...","TWN":"這個感覺，就像……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"응? 뭐야, 저 거인형 괴수는?","JPN":"うん？　なんだ、あの巨人型の怪獣は。","ENG":"Huh? What's that? A giant monster?","TWN":"嗯？什麼啊，那巨型怪獸是什麼？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"놓친 녀석이 남아있었나? 후딱 해치우고 돌아가자고.","JPN":"逃したやつがいたのか？　早くやっつけて戻ろう。","ENG":"Did one slip past us? Let's deal with it and head back.","TWN":"還有漏網之魚嗎？趕緊解決掉然後回去吧。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……안돼.","JPN":"……ダメだ。","ENG":"...No.","TWN":"不行……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"멈춰! 다들 움직이지 마!!","JPN":"止まれ！　みんな、動くな！！","ENG":"Don't move! Everyone stay back!!","TWN":"停下！大家都不要動！！"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"喔？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"뭐야… 내 몸이 왜……?","JPN":"なんだ……体がどうして……？","ENG":"W-What's... happening to my body...?","TWN":"怎麼回事…我的身體怎麼了……？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"모… 몸이, 절단됐어?","JPN":"か……体が、切断された？","ENG":"My– My body's been cut in half?","TWN":"身……身體，被切斷了？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"저놈에게서 느껴지는 독기는, 서, 설마…….","JPN":"あいつから感じられる毒気は、ま、まさか……","ENG":"That poison I sense from it... I-it can't be...","TWN":"從那傢伙身上感受到的殺氣，難道是……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};